const response = $json["output"];
const auctionValue = $('Get Auctions with Surplus List').item.json.id;

const cleaned = response.replace(/^```json|```$/g, '').trim();
const jsonOutput = JSON.parse(cleaned);

// Assuming the root is an object with a "foreclosures" array:
const foreclosures = jsonOutput.foreclosures.map(item => ({
  ...item,
  Auction: [auctionValue]
}));

// Return multiple items correctly
return foreclosures.map(item => ({ json: item }));

return [{
  json: {
    Auctions: $('Get Auctions with Surplus List').all().map(item => item.json.id)
  }
}];
